Convert this complete PostgreSQL schema to DSQL-compatible DDL:

CREATE TYPE status AS ENUM ('active','inactive','suspended');

CREATE TABLE organizations (
  id SERIAL PRIMARY KEY,
  name VARCHAR(200) UNIQUE
);

CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  org_id INT REFERENCES organizations(id) ON DELETE CASCADE,
  email VARCHAR(255) NOT NULL,
  status status DEFAULT 'active',
  preferences JSONB,
  search_tokens TSVECTOR
);

CREATE INDEX idx_users_search ON users USING gin(search_tokens);
CREATE INDEX idx_users_active ON users (email) WHERE status = 'active';

CREATE FUNCTION update_search() RETURNS TRIGGER AS $$
BEGIN
  NEW.search_tokens = to_tsvector(NEW.email);
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;
